var surah050 = {
  number: 50,
  nameArabic: "Qaf",
  nameEnglish: "Qaf",
  meaning: "Qaf",
  totalAyahs: 45,
  ayahs: [
    { number: 1, arabic: "قٓ ۚ وَٱلْقُرْءَانِ ٱلْمَجِيدِ", transliteration: "Qaf waalqurani almajeedi", transliterationB: "Qaaaf; wal Qur aanil Majeed", english: "Qaf: By the Glorious Qur'an (Thou art Allah's Messenger)", romanUrdu: "Qaaf, Kasam hai quran-e-majeed ki" },
    { number: 2, arabic: "بَلْ عَجِبُوٓا۟ أَن جَآءَهُم مُّنذِرٌۭ مِّنْهُمْ فَقَالَ ٱلْكَٰفِرُونَ هَٰذَا شَىْءٌ عَجِيبٌ", transliteration: "Bal AAajiboo an jaahum munthirun minhum faqala alkafiroona hatha shayon AAajeebun", transliterationB: "Bal 'ajibooo an jaa'ahum munzirum minhum faqaalal kaafiroona haazaa shai'un 'ajeeb", english: "But they wonder that there has come to them a Warner from among themselves. So the Unbelievers say: \"This is a wonderful thing", romanUrdu: "Balke in logon ko taajub is baat par hua ke ek khabardar karne wala khud inhi mein se inke paas aa gaya, phir munkireen kehne lagey “yeh to ajeeb baat hai" },
    { number: 3, arabic: "أَءِذَا مِتْنَا وَكُنَّا تُرَابًۭا ۖ ذَٰلِكَ رَجْعٌۢ بَعِيدٌۭ", transliteration: "Aitha mitna wakunna turaban thalika rajAAun baAAeedun", transliterationB: "A-izaa mitnaa wa kunnaa turaaban zaalika raj'um ba'eed", english: "What! When we die and become dust, (shall we live again?) That is a (sort of) return far (from our understanding)", romanUrdu: "Kya jab hum mar jayenge aur khaak (mitti) ho jayenge (to dobara uthaye jayenge)? Yeh wapasi to aqal se baeed hai”" },
    { number: 4, arabic: "قَدْ عَلِمْنَا مَا تَنقُصُ ٱلْأَرْضُ مِنْهُمْ ۖ وَعِندَنَا كِتَٰبٌ حَفِيظٌۢ", transliteration: "Qad AAalimna ma tanqusu alardu minhum waAAindana kitabun hafeethun", transliterationB: "Qad 'alimnaa maa tanqu-sul-ardu minhum wa 'indanaa Kitaabun Hafeez", english: "We already know how much of them the earth takes away: With Us is a record guarding (the full account)", romanUrdu: "Zameen inke jism mein se jo kuch khati hai woh sab hamare ilm mein hai aur hamare paas ek kitaab hai jismein sab kuch mehfooz hai" },
    { number: 5, arabic: "بَلْ كَذَّبُوا۟ بِٱلْحَقِّ لَمَّا جَآءَهُمْ فَهُمْ فِىٓ أَمْرٍۢ مَّرِيجٍ", transliteration: "Bal kaththaboo bialhaqqi lamma jaahum fahum fee amrin mareejin", transliterationB: "Bal kazzaboo bilhaqqi lammaa jaaa'ahum fahum feee amrim mareej", english: "But they deny the Truth when it comes to them: so they are in a confused state", romanUrdu: "Balke in logon ne to jis waqt haqq inke paas aaya usi waqt usey saaf jhutla diya. Isi wajah se ab yeh uljhan mein padey huey hain" },
    { number: 6, arabic: "أَفَلَمْ يَنظُرُوٓا۟ إِلَى ٱلسَّمَآءِ فَوْقَهُمْ كَيْفَ بَنَيْنَٰهَا وَزَيَّنَّٰهَا وَمَا لَهَا مِن فُرُوجٍۢ", transliteration: "Afalam yanthuroo ila alssamai fawqahum kayfa banaynaha wazayyannaha wama laha min furoojin", transliterationB: "Afalam yanzurooo ilas samaaa'i fawqahum kaifa banainaahaa wa zaiyannaahaa wa maa lahaa min furooj", english: "Do they not look at the sky above them?- How We have made it and adorned it, and there are no flaws in it", romanUrdu: "Accha, to kya inhon ne kabhi apne upar aasmaan ki taraf nahin dekha? Kis tarah humne usey banaya aur aarasta (zeenat/ beautify) kiya, aur usmein kahin koi rakhna(cracks/rifts) nahin hai" },
    { number: 7, arabic: "وَٱلْأَرْضَ مَدَدْنَٰهَا وَأَلْقَيْنَا فِيهَا رَوَٰسِىَ وَأَنۢبَتْنَا فِيهَا مِن كُلِّ زَوْجٍۭ بَهِيجٍۢ", transliteration: "Waalarda madadnaha waalqayna feeha rawasiya waanbatna feeha min kulli zawjin baheejin", transliterationB: "Wal arda madadnaahaa wa alqainaa feehaa rawaasiya wa ambatnaa feehaa min kulli zawjim baheej", english: "And the earth- We have spread it out, and set thereon mountains standing firm, and produced therein every kind of beautiful growth (in pairs)", romanUrdu: "Aur zameen ko humne bichaya aur ismein pahadh jamaye aur uske andar har taraah ki khush manzar nabataat uga di" },
    { number: 8, arabic: "تَبْصِرَةًۭ وَذِكْرَىٰ لِكُلِّ عَبْدٍۢ مُّنِيبٍۢ", transliteration: "Tabsiratan wathikra likulli AAabdin muneebin", transliterationB: "Tabsiratanw wa zikraa likulli 'abdim muneeb", english: "To be observed and commemorated by every devotee turning (to Allah)", romanUrdu: "Yeh saari cheezein aankhein kholne wali aur sabaq dene wali hain har us bandey ke liye jo (haqq ki taraf) rujoo karne wala ho" },
    { number: 9, arabic: "وَنَزَّلْنَا مِنَ ٱلسَّمَآءِ مَآءًۭ مُّبَٰرَكًۭا فَأَنۢبَتْنَا بِهِۦ جَنَّٰتٍۢ وَحَبَّ ٱلْحَصِيدِ", transliteration: "Wanazzalna mina alssamai maan mubarakan faanbatna bihi jannatin wahabba alhaseedi", transliterationB: "Wa nazzalnaa minas samaaa'i maaa'am mubaarakan fa ambatnaa bihee jannaatinw wa habbal haseed", english: "And We send down from the sky rain charted with blessing, and We produce therewith gardens and Grain for harvests", romanUrdu: "Aur aasmaan se humne barkat wala paani naazil kiya,phir ussey baagh aur fasal ke galley" },
    { number: 10, arabic: "وَٱلنَّخْلَ بَاسِقَٰتٍۢ لَّهَا طَلْعٌۭ نَّضِيدٌۭ", transliteration: "Waalnnakhla basiqatin laha talAAun nadeedun", transliterationB: "Wannakhla baasiqaatil laha tal'un nadeed", english: "And tall (and stately) palm-trees, with shoots of fruit-stalks, piled one over another", romanUrdu: "Aur buland o baala khajoor ke darakht paida kardiye jinpar phalon(fruits) se ladey khoshey teh-bar-teh lagte (fruit arranged in layers) hain" },
    { number: 11, arabic: "رِّزْقًۭا لِّلْعِبَادِ ۖ وَأَحْيَيْنَا بِهِۦ بَلْدَةًۭ مَّيْتًۭا ۚ كَذَٰلِكَ ٱلْخُرُوجُ", transliteration: "Rizqan lilAAibadi waahyayna bihi baldatan maytan kathalika alkhurooju", transliterationB: "Rizqal lil'ibaad, wa ahyainaa bihee baldatam maitaa; kazaalikal khurooj", english: "As sustenance for (Allah's) Servants;- and We give (new) life therewith to land that is dead: Thus will be the Resurrection", romanUrdu: "Yeh intizaam hai bandon ko rizq dene ka is pani se hum ek murda zameen ko zindagi baksh dete hain (marey huey Insano ka zameen se) nikalne bhi isi tarah hoga" },
    { number: 12, arabic: "كَذَّبَتْ قَبْلَهُمْ قَوْمُ نُوحٍۢ وَأَصْحَٰبُ ٱلرَّسِّ وَثَمُودُ", transliteration: "Kaththabat qablahum qawmu noohin waashabu alrrassi wathamoodu", transliterationB: "Kazzabat qablahum qawmu Noohinw wa Ashaabur Rassi wa Samood", english: "Before them was denied (the Hereafter) by the People of Noah, the Companions of the Rass, the Thamud", romanUrdu: "In se pehle Nooh ki qaum, aur ashab-ur-rass ,aur Samood" },
    { number: 13, arabic: "وَعَادٌۭ وَفِرْعَوْنُ وَإِخْوَٰنُ لُوطٍۢ", transliteration: "WaAAadun wafirAAawnu waikhwanu lootin", transliterationB: "Wa 'Aadunw wa Fir'awnu wikhwaanu loot", english: "The 'Ad, Pharaoh, the brethren of Lut", romanUrdu: "Aur Aad, aur Firoun , aur Lut ke bhai" },
    { number: 14, arabic: "وَأَصْحَٰبُ ٱلْأَيْكَةِ وَقَوْمُ تُبَّعٍۢ ۚ كُلٌّۭ كَذَّبَ ٱلرُّسُلَ فَحَقَّ وَعِيدِ", transliteration: "Waashabu alaykati waqawmu tubbaAAin kullun kaththaba alrrusula fahaqqa waAAeedi", transliterationB: "Wa Ashaabul Aykati wa qawmu Tubba'; kullun kazzabar Rusula fahaqqa wa'eed", english: "The Companions of the Wood, and the People of Tubba'; each one (of them) rejected the messengers, and My warning was duly fulfilled (in them)", romanUrdu: "Aur aykah( dwellers in the wood) wale, aur tubba ki qaum ke log bhi jhutla chuke hain har ek ne Rasoolon ko jhutlaya , aur aakhir e kaar meri waeed(threat) un par chaspan ho gayi" },
    { number: 15, arabic: "أَفَعَيِينَا بِٱلْخَلْقِ ٱلْأَوَّلِ ۚ بَلْ هُمْ فِى لَبْسٍۢ مِّنْ خَلْقٍۢ جَدِيدٍۢ", transliteration: "AfaAAayeena bialkhalqi alawwali bal hum fee labsin min khalqin jadeedin", transliterationB: "Afa'a yeenaa bilkhalqil awwal; bal hum fee labsim min khalqin jadeed", english: "Were We then weary with the first Creation, that they should be in confused doubt about a new Creation", romanUrdu: "Kya pehli baar ki takhleeq(creation) se hum aajiz (worn out) thay? Magar ek nayi takhleeq ki taraf se yeh log shakk mein padey huey hain" },
    { number: 16, arabic: "وَلَقَدْ خَلَقْنَا ٱلْإِنسَٰنَ وَنَعْلَمُ مَا تُوَسْوِسُ بِهِۦ نَفْسُهُۥ ۖ وَنَحْنُ أَقْرَبُ إِلَيْهِ مِنْ حَبْلِ ٱلْوَرِيدِ", transliteration: "Walaqad khalaqna alinsana wanaAAlamu ma tuwaswisu bihi nafsuhu wanahnu aqrabu ilayhi min habli alwareedi", transliterationB: "Wa laqad khalaqnal insaana wa na'lamu maa tuwaswisu bihee nafsuhoo wa Nahnu aqrabu ilaihi min hablil wareed", english: "It was We Who created man, and We know what dark suggestions his soul makes to him: for We are nearer to him than (his) jugular vein", romanUrdu: "Humne Insaan ko paida kiya hai aur uske dil mein ubharne wale waswason tak ko hum jaante hain. Hum to us ki rag-e-gardan(jugular vein) se bhi zyada us se qareeb hain" },
    { number: 17, arabic: "إِذْ يَتَلَقَّى ٱلْمُتَلَقِّيَانِ عَنِ ٱلْيَمِينِ وَعَنِ ٱلشِّمَالِ قَعِيدٌۭ", transliteration: "Ith yatalaqqa almutalaqqiyani AAani alyameeni waAAani alshshimali qaAAeedun", transliterationB: "Iz yatalaqqal mutalaqqi yaani 'anil yameeni wa 'anish shimaali qa'eed", english: "Behold, two (guardian angels) appointed to learn (his doings) learn (and noted them), one sitting on the right and one on the left", romanUrdu: "(aur hamare is barah-e-raast ilm ke alawa)do kaatib(scribes) uske dayein aur bayein baithay(farishtey) har cheez sabt(likh) kar rahe hain" },
    { number: 18, arabic: "مَّا يَلْفِظُ مِن قَوْلٍ إِلَّا لَدَيْهِ رَقِيبٌ عَتِيدٌۭ", transliteration: "Ma yalfithu min qawlin illa ladayhi raqeebun AAateedun", transliterationB: "Maa yalfizu min qawlin illaa ladaihi raqeebun 'ateed", english: "Not a word does he utter but there is a sentinel by him, ready (to note it)", romanUrdu: "Koi lafz us ki zubaan se nahin nikalta jisey mehfooz karne ke liye ek hazir baash nigraan maujood na ho" },
    { number: 19, arabic: "وَجَآءَتْ سَكْرَةُ ٱلْمَوْتِ بِٱلْحَقِّ ۖ ذَٰلِكَ مَا كُنتَ مِنْهُ تَحِيدُ", transliteration: "Wajaat sakratu almawti bialhaqqi thalika ma kunta minhu taheedu", transliterationB: "Wa jaaa'at kullu nafsim ma'ahaa saaa'iqunw wa shaheed", english: "And the stupor of death will bring Truth (before his eyes): \"This was the thing which thou wast trying to escape", romanUrdu: "Phir dekho, woh maut ki jaan-kani (agony of death) haqq lekar aa pahunchi, yeh wahi cheez hai jisse tu bhaaghta tha" },
    { number: 20, arabic: "وَنُفِخَ فِى ٱلصُّورِ ۚ ذَٰلِكَ يَوْمُ ٱلْوَعِيدِ", transliteration: "Wanufikha fee alssoori thalika yawmu alwaAAeedi", transliterationB: "Wa nufikha fis Soor; zaalika yawmul wa'eed", english: "And the Trumpet shall be blown: that will be the Day whereof Warning (had been given)", romanUrdu: "Aur phir sur (trumpet) phoonka gaya, yeh hai woh din jiska tujhe khauf dilaya jata tha" },
    { number: 21, arabic: "وَجَآءَتْ كُلُّ نَفْسٍۢ مَّعَهَا سَآئِقٌۭ وَشَهِيدٌۭ", transliteration: "Wajaat kullu nafsin maAAaha saiqun washaheedun", transliterationB: "Wa jaaa'at kullu nafsim ma'ahaa saaa'iqunw wa shaheed", english: "And there will come forth every soul: with each will be an (angel) to drive, and an (angel) to bear witness", romanUrdu: "Har shaks is haal mein aa gaya ke uske saath ek haank(drive) kar lane wala hai aur ek gawahi dene wala" },
    { number: 22, arabic: "لَّقَدْ كُنتَ فِى غَفْلَةٍۢ مِّنْ هَٰذَا فَكَشَفْنَا عَنكَ غِطَآءَكَ فَبَصَرُكَ ٱلْيَوْمَ حَدِيدٌۭ", transliteration: "Laqad kunta fee ghaflatin min hatha fakashafna AAanka ghitaaka fabasaruka alyawma hadeedun", transliterationB: "Laqad kunta fee ghaf latim min haazaa fakashafnaa 'anka ghitaaa'aka fabasarukal yawma hadeed", english: "(It will be said:) \"Thou wast heedless of this; now have We removed thy veil, and sharp is thy sight this Day", romanUrdu: "Is cheez ki taraf se tu gaflat mein tha, humne woh purda hata diya jo tere aagey pada hua tha aur aaj teri nigaah khoob tez hai" },
    { number: 23, arabic: "وَقَالَ قَرِينُهُۥ هَٰذَا مَا لَدَىَّ عَتِيدٌ", transliteration: "Waqala qareenuhu hatha ma ladayya AAateedun", transliterationB: "Wa qaala qareenuhoo haazaa maa ladaiya 'ateed", english: "And his Companion will say: \"Here is (his Record) ready with me", romanUrdu: "Uske saathi ne arz kiya ye jo meri supurdgi mein tha haazir hai" },
    { number: 24, arabic: "أَلْقِيَا فِى جَهَنَّمَ كُلَّ كَفَّارٍ عَنِيدٍۢ", transliteration: "Alqiya fee jahannama kulla kaffarin AAaneedin", transliterationB: "Alqiyaa fee Jahannama kulla kaffaarin 'aneed", english: "(The sentence will be:) \"Throw, throw into Hell every contumacious Rejecter (of Allah)", romanUrdu: "Hukum diya gaya “phenk do jahannum mein har katte (hardened, stubborn) kaafir ko jo haqq se inaad rakhta tha" },
    { number: 25, arabic: "مَّنَّاعٍۢ لِّلْخَيْرِ مُعْتَدٍۢ مُّرِيبٍ", transliteration: "MannaAAin lilkhayri muAAtadin mureebin", transliterationB: "Mannaa'il lilkhayri mu'tadim mureeb", english: "Who forbade what was good, transgressed all bounds, cast doubts and suspicions", romanUrdu: "Khair ko roakne wala aur hadd se tajauz (exceeds the limits) karne wala tha, shakk mein pada hua tha" },
    { number: 26, arabic: "ٱلَّذِى جَعَلَ مَعَ ٱللَّهِ إِلَٰهًا ءَاخَرَ فَأَلْقِيَاهُ فِى ٱلْعَذَابِ ٱلشَّدِيدِ", transliteration: "Allathee jaAAala maAAa Allahi ilahan akhara faalqiyahu fee alAAathabi alshshadeedi", transliterationB: "Allazee ja'ala ma'al laahi ilaahan aakhara fa alqiyaahu fil'azaabish shadeed", english: "Who set up another god beside Allah: Throw him into a severe penalty", romanUrdu: "Aur Allah ke saath kisi dusre ko khuda banaye baitha tha. Daal do usey sakht azaab mein”" },
    { number: 27, arabic: "۞ قَالَ قَرِينُهُۥ رَبَّنَا مَآ أَطْغَيْتُهُۥ وَلَٰكِن كَانَ فِى ضَلَٰلٍۭ بَعِيدٍۢ", transliteration: "Qala qareenuhu rabbana ma atghaytuhu walakin kana fee dalalin baAAeedin", transliterationB: "Qaala qareenuhoo Rabbanaa maaa atghaituhoo wa laakin kaana fee dalaahim ba'eed", english: "His Companion will say: \"Our Lord! I did not make him transgress, but he was (himself) far astray", romanUrdu: "Uske saathi ne arz kiya “khuda-wanda, maine isko sarkash nahin banaya balke yeh khud hi parle darje ki gumrahi mein pada hua tha”" },
    { number: 28, arabic: "قَالَ لَا تَخْتَصِمُوا۟ لَدَىَّ وَقَدْ قَدَّمْتُ إِلَيْكُم بِٱلْوَعِيدِ", transliteration: "Qala la takhtasimoo ladayya waqad qaddamtu ilaykum bialwaAAeedi", transliterationB: "Qaala laa takhtasimoo ladaayya wa qad qaddamtu ilaikum bilwa'eed", english: "He will say: \"Dispute not with each other in My Presence: I had already in advance sent you Warning", romanUrdu: "Jawab mein irshad hua “mere huzoor jhagda na karo, main tumko pehle hi anjaam-e-badd se khabardar kar chuka tha" },
    { number: 29, arabic: "مَا يُبَدَّلُ ٱلْقَوْلُ لَدَىَّ وَمَآ أَنَا۠ بِظَلَّٰمٍۢ لِّلْعَبِيدِ", transliteration: "Ma yubaddalu alqawlu ladayya wama ana bithallamin lilAAabeedi", transliterationB: "Maa yubaddalul qawlu ladaiya wa maaa ana bizal laamil lil'abeed", english: "The Word changes not before Me, and I do not the least injustice to My Servants", romanUrdu: "Mere haan (yahan) baat palti nahin jaati aur main apne bandon par zulm todhne wala nahin hoon”" },
    { number: 30, arabic: "يَوْمَ نَقُولُ لِجَهَنَّمَ هَلِ ٱمْتَلَأْتِ وَتَقُولُ هَلْ مِن مَّزِيدٍۢ", transliteration: "Yawma naqoolu lijahannama hali imtalati wataqoolu hal min mazeedin", transliterationB: "Yawma naqoolu li'jahannama halim talaati wa taqoolu hal mim mazeed", english: "One Day We will ask Hell, \"Art thou filled to the full?\" It will say, \"Are there any more (to come)", romanUrdu: "Woh din jabke hum jahannum se puchenge kya tu bhar gayi? Aur woh kahegi kya aur kuch hai" },
    { number: 31, arabic: "وَأُزْلِفَتِ ٱلْجَنَّةُ لِلْمُتَّقِينَ غَيْرَ بَعِيدٍ", transliteration: "Waozlifati aljannatu lilmuttaqeena ghayra baAAeedin", transliterationB: "Wa uzlifatil jannatu lil muttaqeena ghaira ba'eed", english: "And the Garden will be brought nigh to the Righteous,- no more a thing distant", romanUrdu: "Aur Jannat muttaqin ke qareeb le aayi jayegi, kuch bhi dur na hogi" },
    { number: 32, arabic: "هَٰذَا مَا تُوعَدُونَ لِكُلِّ أَوَّابٍ حَفِيظٍۢ", transliteration: "Hatha ma tooAAadoona likulli awwabin hafeethin", transliterationB: "Haaza maa too'adoona likulli awwaabin hafeez", english: "(A voice will say:) \"This is what was promised for you,- for every one who turned (to Allah) in sincere repentance, who kept (His Law)", romanUrdu: "Irshad hoga “yeh hai woh cheez jiska tumse waada kiya jata tha, har us shaks ke liye jo bahut rujoo karne wala aur badi nigehdaasht (watchful of his conduct) karne wala tha" },
    { number: 33, arabic: "مَّنْ خَشِىَ ٱلرَّحْمَٰنَ بِٱلْغَيْبِ وَجَآءَ بِقَلْبٍۢ مُّنِيبٍ", transliteration: "Man khashiya alrrahmana bialghaybi wajaa biqalbin muneebin", transliterationB: "Man khashiyar Rahmaana bilghaibi wa jaaa'a biqalbim muneeb", english: "Who feared (Allah) Most Gracious Unseen, and brought a heart turned in devotion (to Him)", romanUrdu: "Jo bay dekhe Rehman se darta tha, aur jo dil-e-girwida liye huey aaya hai" },
    { number: 34, arabic: "ٱدْخُلُوهَا بِسَلَٰمٍۢ ۖ ذَٰلِكَ يَوْمُ ٱلْخُلُودِ", transliteration: "Odkhulooha bisalamin thalika yawmu alkhuloodi", transliterationB: "Udkhuloohaa bisalaamin zaalika yawmul khulood", english: "Enter ye therein in Peace and Security; this is a Day of Eternal Life", romanUrdu: "Dakhil ho jao Jannat mein salamati ke saath” woh din hayat-e-abadi (eternity) ka din hoga" },
    { number: 35, arabic: "لَهُم مَّا يَشَآءُونَ فِيهَا وَلَدَيْنَا مَزِيدٌۭ", transliteration: "Lahum ma yashaoona feeha waladayna mazeedun", transliterationB: "Lahum maa yashaaa'oona feehaa wa ladainaa mazeed", english: "There will be for them therein all that they wish,- and more besides in Our Presence", romanUrdu: "Wahan unke liye woh sab kuch hoga jo woh chahenge, aur hamare paas issey zyada bhi bahut kuch unke liye hai" },
    { number: 36, arabic: "وَكَمْ أَهْلَكْنَا قَبْلَهُم مِّن قَرْنٍ هُمْ أَشَدُّ مِنْهُم بَطْشًۭا فَنَقَّبُوا۟ فِى ٱلْبِلَٰدِ هَلْ مِن مَّحِيصٍ", transliteration: "Wakam ahlakna qablahum min qarnin hum ashaddu minhum batshan fanaqqaboo fee albiladi hal min maheesin", transliterationB: "Wa kam ahlaknaa qablahum min qarnin hum ashaddu minhum batshan fanaqqaboo fil bilaad, hal mim mahees", english: "But how many generations before them did We destroy (for their sins),- stronger in power than they? Then did they wander through the land: was there any place of escape (for them)", romanUrdu: "Hum unse pehle bahut si qaumon ko halaak kar chuke hain jo insey bahut zyada taaqatwar thi aur duniya ke mulkon ko unhon ne chaan maara tha phir kya woh koi jaaye panaah paa sakey" },
    { number: 37, arabic: "إِنَّ فِى ذَٰلِكَ لَذِكْرَىٰ لِمَن كَانَ لَهُۥ قَلْبٌ أَوْ أَلْقَى ٱلسَّمْعَ وَهُوَ شَهِيدٌۭ", transliteration: "Inna fee thalika lathikra liman kana lahu qalbun aw alqa alssamAAa wahuwa shaheedun", transliterationB: "Inna fee zaalika lazikraa liman kaana lahoo qalbun aw alqas sam'a wa huwa shaheed", english: "Verily in this is a Message for any that has a heart and understanding or who gives ear and earnestly witnesses (the truth)", romanUrdu: "Is tareekh mein ibrat ka sabaq hai har us shaks ke liye jo dil rakhta ho, ya jo tawajju se baat ko suney" },
    { number: 38, arabic: "وَلَقَدْ خَلَقْنَا ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ وَمَا بَيْنَهُمَا فِى سِتَّةِ أَيَّامٍۢ وَمَا مَسَّنَا مِن لُّغُوبٍۢ", transliteration: "Walaqad khalaqna alssamawati waalarda wama baynahuma fee sittati ayyamin wama massana min lughoobin", transliterationB: "Wa laqad khalaqnas samaawaati wal arda wa maa bainahumaa fee sittati ayyaamin wa maa massanaa mil lughoob", english: "We created the heavens and the earth and all between them in Six Days, nor did any sense of weariness touch Us", romanUrdu: "Humne zameen aur aasmaano ko aur unke darmiyan ki saari cheezon ko chey(six) dino mein paida kardiya aur humein koi thakaan laahiq na hui" },
    { number: 39, arabic: "فَٱصْبِرْ عَلَىٰ مَا يَقُولُونَ وَسَبِّحْ بِحَمْدِ رَبِّكَ قَبْلَ طُلُوعِ ٱلشَّمْسِ وَقَبْلَ ٱلْغُرُوبِ", transliteration: "Faisbir AAala ma yaqooloona wasabbih bihamdi rabbika qabla tulooAAi alshshamsi waqabla alghuroobi", transliterationB: "Fasbir 'alaa maa yaqooloona wa sabbih bihamdi Rabbika qabla tuloo'ish shamsi wa qablal ghuroob", english: "Bear, then, with patience, all that they say, and celebrate the praises of thy Lord, before the rising of the sun and before (its) setting", romanUrdu: "Pas aey Nabi, jo baatein yeh log banate hain unpar sabr karo, aur apne Rubb ki hamd ke saath uski tasbeeh karte raho, tulu-e-aftaab( rising of the sun ) aur guroob-e-aftaab( before its setting ) se pehle" },
    { number: 40, arabic: "وَمِنَ ٱلَّيْلِ فَسَبِّحْهُ وَأَدْبَٰرَ ٱلسُّجُودِ", transliteration: "Wamina allayli fasabbihhu waadbara alssujoodi", transliterationB: "Wa minal laili fasabbih hu wa adbaaras sujood", english: "And during part of the night, (also,) celebrate His praises, and (so likewise) after the postures of adoration", romanUrdu: "Aur raat ke waqt phir uski tasbeeh karo aur sajda reizion se faarig honay ke baad bhi(wake of prostration)" },
    { number: 41, arabic: "وَٱسْتَمِعْ يَوْمَ يُنَادِ ٱلْمُنَادِ مِن مَّكَانٍۢ قَرِيبٍۢ", transliteration: "WaistamiAA yawma yunadi almunadi min makanin qareebin", transliterationB: "Wastami' yawma yunaa dil munaadi mim makaanin qareeb", english: "And listen for the Day when the Caller will call out from a place quiet near", romanUrdu: "Aur suno, jis din munadi (pukaar) karne wala (har shaks ke)qareeb hi se pukarega" },
    { number: 42, arabic: "يَوْمَ يَسْمَعُونَ ٱلصَّيْحَةَ بِٱلْحَقِّ ۚ ذَٰلِكَ يَوْمُ ٱلْخُرُوجِ", transliteration: "Yawma yasmaAAoona alssayhata bialhaqqi thalika yawmu alkhurooji", transliterationB: "Yawma yasmaoonas sai hata bilhaqq zaalika yawmul khurooj", english: "The Day when they will hear a (mighty) Blast in (very) truth: that will be the Day of Resurrection", romanUrdu: "Jis din sab log aawaza-e-hashar ko theek theek sun rahey honge, woh zameen se murdon ke nikalne ka din hoga" },
    { number: 43, arabic: "إِنَّا نَحْنُ نُحْىِۦ وَنُمِيتُ وَإِلَيْنَا ٱلْمَصِيرُ", transliteration: "Inna nahnu nuhyee wanumeetu wailayna almaseeru", transliterationB: "Innaa Nahnu nuhyee wa numeetu wa ilainal maseer", english: "Verily it is We Who give Life and Death; and to Us is the Final Goal", romanUrdu: "Hum hi zindagi bakshte hain aur hum hi maut detey hain, aur hamari hi taraf us din sabko palatna hai" },
    { number: 44, arabic: "يَوْمَ تَشَقَّقُ ٱلْأَرْضُ عَنْهُمْ سِرَاعًۭا ۚ ذَٰلِكَ حَشْرٌ عَلَيْنَا يَسِيرٌۭ", transliteration: "Yawma tashaqqaqu alardu AAanhum siraAAan thalika hashrun AAalayna yaseerun", transliterationB: "Yawma tashaqqaqul ardu 'anhum siraa'aa; zaalika hashrun 'alainaa yaseer", english: "The Day when the Earth will be rent asunder, from (men) hurrying out: that will be a gathering together,- quite easy for Us", romanUrdu: "Jab zameen phategi log uske andar se nikal kar teiz teiz bhage ja rahe honge. Yeh hashar hamare liye bahut aasaan hai" },
    { number: 45, arabic: "نَّحْنُ أَعْلَمُ بِمَا يَقُولُونَ ۖ وَمَآ أَنتَ عَلَيْهِم بِجَبَّارٍۢ ۖ فَذَكِّرْ بِٱلْقُرْءَانِ مَن يَخَافُ وَعِيدِ", transliteration: "Nahnu aAAlamu bima yaqooloona wama anta AAalayhim bijabbarin fathakkir bialqurani man yakhafu waAAeedi", transliterationB: "Nahnu a'lamu bimaa yaqooloona wa maaa anta 'alihim bijabbaarin fazakkir bil quraani many yakhaafu wa'eed", english: "We know best what they say; and thou art not one to overawe them by force. So admonish with the Qur'an such as fear My Warning", romanUrdu: "Aey Nabi, jo baatein yeh log bana rahe hain unhein hum khoob jaante hain, aur tumhara kaam inse jabran (zabardasti) baat manwana nahin hai. Bas tum is Quran ke zariye se har us shaks ko nasihat kardo jo meri tambeeh se darey" }
  ]
};
